INSERT INTO info_utc (utc_id, descricao, curiosidade, imagem_url, video_url) VALUES
(1, 'Região do Pacífico Sul com clima tropical, marcada por calor, umidade e forte influência marítima.', 'Uma das últimas regiões do mundo a encerrar o dia.', 'https://commons.wikimedia.org/wiki/Special:Redirect/file/Pago%20Pago%20-%20View%20of%20harbor.jpg', 'https://www.youtube.com/watch?v=Y6DHkgMplDw'),
(2, 'Arquipélago brasileiro com paisagens costeiras, clima quente e presença de períodos secos e chuvosos ao longo do ano.', 'Famoso pelo turismo ecológico.', 'https://commons.wikimedia.org/wiki/Special:Redirect/file/Fernando%20de%20noronha%204.jpg', 'https://www.youtube.com/watch?v=9bDYNPXkZ0g'),
(3, 'Região asiática de clima úmido, com destaque para calor intenso e chuvas associadas ao regime de monções.', 'Sofre com monções frequentes.', 'https://commons.wikimedia.org/wiki/Special:Redirect/file/City%20of%20Dhaka%20skyline.jpg', 'https://www.youtube.com/watch?v=qZqWzt5dhYg'),
(4, 'Região quente da Oceania, conhecida por alternar entre estação seca e estação chuvosa em cenários tropicais.', 'Possui estação seca e chuvosa.', 'https://commons.wikimedia.org/wiki/Special:Redirect/file/Darwin%20Waterfront%2C%20September%202025%2004.jpg', 'https://www.youtube.com/watch?v=FPwtE9a-pbQ'),
(5, 'Região do Pacífico com forte identidade insular, mar aberto e paisagens ligadas ao clima tropical oceânico.', 'Uma das primeiras a ver o nascer do sol.', 'https://commons.wikimedia.org/wiki/Special:Redirect/file/Nuku%E2%80%99alofa%2C%20Tonga.jpg', 'https://www.youtube.com/watch?v=I2MFEXYknfo');
